using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x = 0, f = 1;
		char ch = gc();
		wh(ch < '0' || ch > '9')
		{
			if (ch == '-')f = -1;
			ch = getchar();
		}
		wh(ch >= '0' && ch <= '9')
		{
			x = x * 10 + ch - '0';
			ch = gc();
		}
		return x * f;
	}
	void write(ll x)
	{
		if (x < 0)pc('-'), x = -x;
		if (x > 9)write(x / 10);
		pc(x % 10 + '0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
const int maxn = 1005;
int n, m, s, t, g[maxn][maxn], in[maxn], a[maxn], b[maxn], h[maxn], f[maxn];
queue<int>q;
void topsort()
{
	for (int i = 1; i <= n; i++)
	{
		if (!in[i])
		{
			q.push(i);
			f[i] = 1;
		}
	}
	int ans = 1;
	while (!q.empty())
	{
		int u = q.front();
		q.pop();
		ans = max(ans, f[u]);
		for (int i = 1; i <= n; i++)
		{
			if (!g[u][i])
			{
				continue;
			}
			in[i] -= g[u][i];
			f[i] = max(f[i], f[u] + 1);
			if (!in[i])
			{
				q.push(i);
			}
		}
	}
	cout << ans;
}
signed main(void)
{
	cin >> n >> m;
	for (int i = 1; i <= m; i++)
	{
		cin >> s;
		for (int j = 1; j <= s; j++)
		{
			cin >> a[j];
		}
		t = 0;
		for (int j = a[1]; j <= a[s]; j++)
		{
			h[j] = 0;
		}
		for (int j = 1; j <= s; j++)
		{
			h[a[j]] = 1;
		}
		for (int j = a[1]; j <= a[s]; j++)
		{
			if (!h[j])
			{
				b[++t] = j;
			}
		}
		for (int j = 1; j <= s; j++)
		{
			for (int k = 1; k <= t; k++)
			{
				g[a[j]][b[k]]++;
				in[b[k]]++;
			}
		}
	}
	topsort();
	return false;
}
